#include <bits/stdc++.h>
using namespace std;
int n,a,b,c;
long long ans[200005];
const int mod=1e9+7;
long long dfs(int x)
{
    if(x<=c) return 1;
    if(ans[x]) return ans[x];
    return ans[x]=(dfs(x-a)%mod+dfs(x-b)%mod)%mod;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>a>>b>>c;
    cout<<dfs(n);
    return 0;
}
